typedef vector<ii> vii;

vector<vil> graph;

vector<ll> dist;

void dijkstra()

{

	dist[1] = 0ll;

	priority_queue<li,vector<li>,greater<li> >pq;

	pq.push(li(0ll,1));

	while(!pq.empty())

	{

		li x = pq.top();pq.pop();

		ll a = x.first;

		int b = x.second;

		if(dist[b]==a)

		{

			for(int i=0;i<graph[b].size();++i)

			{

				il c = graph[b][i];

				if(dist[c.first]==-1||dist[c.first] > dist[b] + c.second)

				{

					dist[c.first] = dist[b] + c.second;

					pq.push(li(dist[c.first],c.first));

				}

			}

		}

	}

}

