void dijkstra()

{

	dist[1] = 0ll;

	priority_queue<li,vector<li>,greater<li> >pq;

	pq.push(li(0ll,1));

	while(!pq.empty())

	{

		li x = pq.top();pq.pop();

		ll a = x.first;

		int b = x.second;

		if(dist[b]==a)

